import requests
from requests.exceptions import RequestException

class OllamaClient:
    def __init__(self, base_url='http://localhost:11434', timeout=30):
        self.base_url = base_url
        self.timeout = timeout

    def _request(self, method, endpoint, **kwargs):
        url = f'{self.base_url}/{endpoint}'
        try:
            response = requests.request(
                method=method,
                url=url,
                timeout=self.timeout,
                **kwargs
            )
            response.raise_for_status()
            return response.json()
        except RequestException as e:
            raise RuntimeError(f"Ollama API error: {str(e)}") from e

    def list_models(self):
        return self._request('GET', 'models')

    def create_model(self, name):
        return self._request('POST', 'models', json={'name': name})

    def generate(self, model, prompt):
        return self._request('POST', 'generate', json={'model': model, 'prompt': prompt})

